#!/usr/bin/env python3
import socket, ipaddress, sys
from concurrent.futures import ThreadPoolExecutor, as_completed
subnet = ipaddress.ip_network('172.19.0.0/24')
port=8000
timeout=0.3

def check(ip):
    s=socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.settimeout(timeout)
    try:
        s.connect((str(ip), port))
        return str(ip)
    except Exception:
        return None
    finally:
        try: s.close()
        except: pass

ips=list(subnet.hosts())
found=[]
with ThreadPoolExecutor(max_workers=128) as ex:
    futs={ex.submit(check, ip): ip for ip in ips}
    for f in as_completed(futs):
        r=f.result()
        if r:
            found.append(r)
            print('OPEN', r, flush=True)
print('FOUND', found)

#!/usr/bin/env python3
import socket
import ipaddress
import sys

def check(ip, port=8000, timeout=0.2):
    s=socket.socket()
    s.settimeout(timeout)
    try:
        s.connect((str(ip),port))
        return True
    except Exception:
        return False
    finally:
        try: s.close()
        except: pass

def main():
    net = ipaddress.ip_network('172.19.0.0/24')
    open_ips=[]
    for ip in net.hosts():
        if check(ip):
            print(f"OPEN {ip}:8000")
            open_ips.append(str(ip))
    if not open_ips:
        print('No hosts with 8000 open found', file=sys.stderr)
    else:
        print('Found:', ', '.join(open_ips))

if __name__=='__main__':
    main()

